// src/components/admin/PacksTable.jsx
import { useState } from "react";
import DataTable from "./DataTable";
import api from "../../utils/api";
import AdminFormDialog from "./dialogs/AdminFormDialog";

export default function PacksTable() {
  const [selectedPack, setSelectedPack] = useState(null);
  const [open, setOpen] = useState(false);

  const packColumns = [
    // size, price, affixChance, rarityDistribution
    { field: "name", headerName: "Name" },
    { field: "description", headerName: "Description" },
    { field: "size", headerName: "Size" },
    { field: "price", headerName: "Price" },
    { field: "affixChance", headerName: "Affix Chance (1-100)%" },
    { field: "rarityDistribution", headerName: "rarityDistribution" },
  ];

  const fetchPacks = async ({ page, limit, search }) => {
    const params = { page: page + 1, limit, search };
    return await api.get("/packs", { params });
  };

  const handleEdit = (pack) => {
    setSelectedPack(pack);
    setOpen(true);
  };

  const handleDelete = async (pack) => {
    if (confirm(`Delete pack ${pack.name}?`)) {
      await api.delete(`/packs/${pack._id}`);
      window.location.reload();
    }
  };

  return (
    <>
      <DataTable
        fetchData={fetchPacks}
        columns={packColumns}
        onEdit={handleEdit}
        onDelete={handleDelete}
      />
      {open && (
        <AdminFormDialog
          entity={selectedPack}
          endpoint="/packs"
          columns={packColumns}
          title="Pack"
          onClose={() => {
            setOpen(false);
            window.location.reload();
          }}
        />
      )}
    </>
  );
}
