// src/components/admin/CardsTable.jsx
import { useState } from "react";
import DataTable from "./DataTable";
import api from "../../utils/api";
import AdminFormDialog from "./dialogs/AdminFormDialog";

export default function CardsTable() {
  const [selectedCard, setSelectedCard] = useState(null);
  const [open, setOpen] = useState(false);

  const cardColumns = [
    { field: "uniqueId", headerName: "Card ID" },
    { field: "description", headerName: "Description" },
    { field: "imageUrl", headerName: "Image URL" },
    { field: "attack", headerName: "Attack", type: "number" },
    { field: "hp", headerName: "HP", type: "number" },
    { field: "speed", headerName: "Speed", type: "number" },
    { field: "value", headerName: "Value", type: "number" },
  ];

  const fetchCards = async ({ page, limit, search }) => {
    const params = { page: page + 1, limit, search };
    return await api.get("/cards", { params }); // backend route should support pagination + search
  };

  const handleEdit = (card) => {
    setSelectedCard(card);
    setOpen(true);
  };

  const handleDelete = async (card) => {
    if (confirm(`Delete card ${card.uniqueId}?`)) {
      await api.delete(`/cards/${card._id}`);
      window.location.reload();
    }
  };

  return (
    <>
      <DataTable
        fetchData={fetchCards}
        columns={cardColumns}
        onEdit={handleEdit}
        onDelete={handleDelete}
      />
      {open && (
        <AdminFormDialog
          entity={selectedCard}
          endpoint="/cards"
          columns={cardColumns}
          title="Cards"
          onClose={() => {
            setOpen(false);
            window.location.reload();
          }}
        />
      )}
    </>
  );
}
