import {
  Card,
  CardMedia,
  CardContent,
  Typography,
  Box,
  Chip,
  Stack,
  Tooltip,
} from "@mui/material";

const rarityColors = {
  common: "#808080",
  uncommon: "#00ff00",
  rare: "#0080ff",
  epic: "#8000ff",
  legendary: "#ff8000",
};

const rarityEmojis = {
  common: "⚪",
  uncommon: "🟢",
  rare: "🔵",
  epic: "🟣",
  legendary: "🟠",
};

const affixEmojis = {
  Shiny: "✨",
  Angry: "😠",
  Tough: "🛡️",
  Swift: "⚡",
  Blessed: "🌟",
};

export default function GalleryCard({ card }) {
  const {
    name,
    description,
    imageUrl,
    hp,
    attack,
    speed,
    rarity = "common",
    value,
    type,
    affixes = [],
    quantity,
    modifiedStats,
  } = card;

  const stats = modifiedStats ?? { hp, attack, speed };

  return (
    <Card
      sx={{
        height: 420, // ⭐ fixed height
        display: "flex",
        flexDirection: "column",
        border: `2px solid ${rarityColors[rarity] || rarityColors.common}`,
        borderRadius: 3,
        position: "relative",
        transition: "0.2s",
        "&:hover": {
          transform: "translateY(-4px) scale(1.02)",
          boxShadow: 6,
        },
      }}
    >
      {/* Quantity badge */}
      {quantity > 1 && (
        <Box
          sx={{
            position: "absolute",
            top: 8,
            right: 8,
            background: "#000",
            color: "#fff",
            px: 1,
            borderRadius: 1,
            fontSize: 12,
            zIndex: 2,
          }}
        >
          x{quantity}
        </Box>
      )}

      {/* Image */}
      <CardMedia component="img" height="160" image={imageUrl} />

      {/* Content */}
      <CardContent
        sx={{
          display: "flex",
          flexDirection: "column",
          flexGrow: 1,
          overflow: "hidden",
        }}
      >
        {/* Title */}
        <Typography fontWeight={700}>
          <Tooltip title={`Rarity: ${rarity}`}>
            <span>{rarityEmojis[rarity]}</span>
          </Tooltip>{" "}
          {name}{" "}
          {affixes?.map((a) => (
            <Tooltip key={a} title={`Affix: ${a}`}>
              <span style={{ marginLeft: 4 }}>{affixEmojis[a] || a}</span>
            </Tooltip>
          ))}
        </Typography>

        {/* Stats */}
        <Typography variant="body2" sx={{ mt: 1 }}>
          HP: {stats.hp} | ATK: {stats.attack} | SPD: {stats.speed}
        </Typography>

        {/* Scrollable Description */}
        <Box
          sx={{
            mt: 1,
            flexGrow: 1,
            overflowY: "auto", // ⭐ scrollable text
            pr: 1,
          }}
        >
          <Typography variant="body2" color="text.secondary">
            {description}
          </Typography>
        </Box>

        {/* Metadata */}
        <Stack direction="row" spacing={1} sx={{ mt: 1, flexWrap: "wrap" }}>
          {value !== undefined && (
            <Tooltip title="Card Value">
              <Chip label={`${value} 💰`} size="small" />
            </Tooltip>
          )}

          {type && (
            <Tooltip title="Card Type">
              <Chip label={type} size="small" />
            </Tooltip>
          )}

          <Chip label={rarity} size="small" />
        </Stack>
      </CardContent>
    </Card>
  );
}
