import { useState, useEffect } from "react";
import {
  Table,
  TableHead,
  TableRow,
  TableCell,
  TableBody,
  TablePagination,
  IconButton,
  TextField,
  Box,
} from "@mui/material";
import { Edit, Delete } from "@mui/icons-material";

/**
 * Safely resolve nested values like "settings.username"
 */
function getValue(obj, path) {
  if (!path) return "";
  return path.split(".").reduce((acc, part) => acc?.[part], obj);
}

/**
 * Default renderer for table values
 */
function renderValue(value) {
  if (value === null || value === undefined) return "";

  if (Array.isArray(value)) {
    return value.join(", ");
  }

  if (typeof value === "object") {
    // Try to display something readable
    if (value.name) return value.name;
    if (value.username) return value.username;
    return JSON.stringify(value);
  }

  return value.toString();
}

export default function DataTable({ fetchData, columns, onEdit, onDelete }) {
  const [data, setData] = useState([]);
  const [page, setPage] = useState(0);
  const [rowsPerPage, setRowsPerPage] = useState(10);
  const [search, setSearch] = useState("");
  const [loading, setLoading] = useState(true);
  const [total, setTotal] = useState(0);

  const loadData = async () => {
    setLoading(true);
    try {
      const response = await fetchData({
        page,
        limit: rowsPerPage,
        search,
      });

      setData(response.data);
      setTotal(response.total);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, [page, rowsPerPage, search]);

  return (
    <Box>
      <TextField
        label="Search"
        variant="outlined"
        size="small"
        value={search}
        onChange={(e) => {
          setSearch(e.target.value);
          setPage(0);
        }}
        sx={{ mb: 2 }}
      />

      <Table>
        <TableHead>
          <TableRow>
            {columns?.map((col) => (
              <TableCell key={col.field}>{col.headerName}</TableCell>
            ))}
            <TableCell>Actions</TableCell>
          </TableRow>
        </TableHead>

        <TableBody>
          {loading ? (
            <TableRow>
              <TableCell colSpan={columns.length + 1}>Loading...</TableCell>
            </TableRow>
          ) : data?.length === 0 ? (
            <TableRow>
              <TableCell colSpan={columns.length + 1}>
                No records found
              </TableCell>
            </TableRow>
          ) : (
            data.map((row) => (
              <TableRow key={row._id}>
                {columns.map((col) => {
                  const rawValue = getValue(row, col.field);

                  return (
                    <TableCell key={row._id + col.field}>
                      {col.render
                        ? col.render(rawValue, row) // custom renderer support
                        : renderValue(rawValue)}
                    </TableCell>
                  );
                })}

                <TableCell>
                  <IconButton onClick={() => onEdit(row)}>
                    <Edit />
                  </IconButton>
                  <IconButton onClick={() => onDelete(row)}>
                    <Delete />
                  </IconButton>
                </TableCell>
              </TableRow>
            ))
          )}
        </TableBody>
      </Table>

      <TablePagination
        component="div"
        count={total}
        page={page}
        onPageChange={(e, newPage) => setPage(newPage)}
        rowsPerPage={rowsPerPage}
        onRowsPerPageChange={(e) =>
          setRowsPerPage(parseInt(e.target.value, 10))
        }
      />
    </Box>
  );
}
