import { useState, useEffect } from 'react'
import { Box, Typography, Paper, Grid, CircularProgress } from '@mui/material'
import { PieChart, Pie, Cell, ResponsiveContainer, Legend, Tooltip } from 'recharts'
import { useAuth } from '../contexts/AuthContext'
import api from '../utils/api'

function Dashboard() {
  const { user } = useAuth()
  const [cardStats, setCardStats] = useState(null)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    const fetchCardStats = async () => {
      try {
        const stats = await api.get('/cards/stats')
        setCardStats(stats)
      } catch (error) {
        console.error('Error fetching card statistics:', error)
        setCardStats({ total: 0, byRarity: { common: 0, uncommon: 0, rare: 0, epic: 0, legendary: 0 } })
      } finally {
        setLoading(false)
      }
    }

    if (user) {
      fetchCardStats()
    }
  }, [user])

  const rarityColors = {
    common: '#9e9e9e',      // Grey
    uncommon: '#4caf50',   // Green
    rare: '#2196f3',        // Blue
    epic: '#9c27b0',        // Purple
    legendary: '#ff9800',   // Orange
  }

  const rarityLabels = {
    common: 'Common',
    uncommon: 'Uncommon',
    rare: 'Rare',
    epic: 'Epic',
    legendary: 'Legendary',
  }

  // Prepare data for pie chart
  const chartData = cardStats?.byRarity
    ? Object.entries(cardStats.byRarity)
        .map(([rarity, count]) => ({
          name: rarityLabels[rarity],
          value: count,
          color: rarityColors[rarity],
        }))
        .filter((item) => item.value > 0) // Only show rarities with cards
    : []

  return (
    <Box sx={{ p: 3 }}>
      <Grid container spacing={3}>
        {/* Welcome and Balance Section */}
        <Grid item xs={12} md={6}>
          <Paper sx={{ p: 3 }}>
            <Typography variant="h4" component="h1" gutterBottom>
              Welcome, {user?.settings?.username || 'Summoner'}!
            </Typography>
            <Typography variant="body1" color="text.secondary" sx={{ mb: 3 }}>
              Your Collection Overview
            </Typography>
            <Box sx={{ display: 'flex', alignItems: 'baseline', gap: 1 }}>
              <Typography variant="h6" color="text.secondary">
                Balance:
              </Typography>
              <Typography variant="h4" color="primary">
                {user?.balance || 0} coins
              </Typography>
            </Box>
          </Paper>
        </Grid>

        {/* Total Cards and Pie Chart Section */}
        <Grid item xs={12} md={6}>
          <Paper sx={{ p: 3 }}>
            <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 2 }}>
              <Typography variant="h6">
                Total Cards
              </Typography>
              {loading ? (
                <CircularProgress size={24} />
              ) : (
                <Typography variant="h4" color="primary">
                  {cardStats?.total || 0}
                </Typography>
              )}
            </Box>
            {loading ? (
              <Box sx={{ display: 'flex', justifyContent: 'center', py: 4 }}>
                <CircularProgress />
              </Box>
            ) : cardStats?.total === 0 ? (
              <Box sx={{ display: 'flex', justifyContent: 'center', py: 4 }}>
                <Typography variant="body1" color="text.secondary">
                  No cards in your collection yet
                </Typography>
              </Box>
            ) : (
              <ResponsiveContainer width="100%" height={300}>
                <PieChart>
                  <Pie
                    data={chartData}
                    cx="50%"
                    cy="50%"
                    labelLine={false}
                    label={({ name, percent }) => `${name}: ${(percent * 100).toFixed(0)}%`}
                    outerRadius={100}
                    fill="#8884d8"
                    dataKey="value"
                  >
                    {chartData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={entry.color} />
                    ))}
                  </Pie>
                  <Tooltip 
                    formatter={(value) => [value, 'Cards']}
                  />
                  <Legend />
                </PieChart>
              </ResponsiveContainer>
            )}
          </Paper>
        </Grid>
      </Grid>
    </Box>
  )
}

export default Dashboard



