import { useState, useEffect } from "react";
import {
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Button,
  TextField,
} from "@mui/material";
import api from "../../../utils/api";

export default function AdminFormDialog({
  entity,
  endpoint,
  columns,
  title,
  onClose,
}) {
  const isEdit = Boolean(entity);
  const [form, setForm] = useState({});

  // Convert objects/arrays to JSON strings for editing
  const serializeValue = (value) => {
    if (value === null || value === undefined) return "";
    if (typeof value === "object") {
      try {
        return JSON.stringify(value, null, 2);
      } catch {
        return "";
      }
    }
    return value;
  };

  // Try to parse JSON before sending to API
  const deserializeValue = (value) => {
    if (typeof value !== "string") return value;

    const trimmed = value.trim();

    // detect JSON objects or arrays
    if (
      (trimmed.startsWith("{") && trimmed.endsWith("}")) ||
      (trimmed.startsWith("[") && trimmed.endsWith("]"))
    ) {
      try {
        return JSON.parse(trimmed);
      } catch {
        return value; // fallback if invalid JSON
      }
    }

    return value;
  };

  useEffect(() => {
    if (entity) {
      const serialized = {};
      columns.forEach((c) => {
        serialized[c.field] = serializeValue(entity[c.field]);
      });
      setForm(serialized);
    } else {
      const initial = {};
      columns.forEach((c) => {
        initial[c.field] = "";
      });
      setForm(initial);
    }
  }, [entity, columns]);

  const handleChange = (field, value) => {
    setForm((prev) => ({ ...prev, [field]: value }));
  };

  const handleSubmit = async () => {
    try {
      const payload = {};

      Object.entries(form).forEach(([key, value]) => {
        payload[key] = deserializeValue(value);
      });

      if (isEdit) {
        await api.patch(`${endpoint}/${entity._id}`, payload);
      } else {
        await api.post(endpoint, payload);
      }

      onClose(true);
    } catch (err) {
      console.error("Save error:", err);
      alert("Failed to save");
    }
  };

  return (
    <Dialog open onClose={() => onClose(false)} fullWidth maxWidth="sm">
      <DialogTitle>{isEdit ? `Edit ${title}` : `Create ${title}`}</DialogTitle>

      <DialogContent dividers>
        {columns.map((col) => {
          if (col.hideInForm) return null;

          const value = form[col.field] ?? "";

          return (
            <TextField
              key={col.field}
              label={col.headerName}
              value={value}
              type={col.type === "number" ? "number" : "text"}
              multiline={true}
              minRows={
                typeof value === "string" && value.includes("\n") ? 4 : 1
              }
              onChange={(e) => handleChange(col.field, e.target.value)}
              fullWidth
              margin="normal"
            />
          );
        })}
      </DialogContent>

      <DialogActions>
        <Button onClick={() => onClose(false)}>Cancel</Button>
        <Button onClick={handleSubmit} variant="contained">
          {isEdit ? "Save" : "Create"}
        </Button>
      </DialogActions>
    </Dialog>
  );
}
