// src/components/admin/UsersTable.jsx
import { useState } from "react";
import DataTable from "./DataTable";
import api from "../../utils/api";
import AdminFormDialog from "./dialogs/AdminFormDialog";

export default function UsersTable() {
  const [selectedUser, setSelectedUser] = useState(null);
  const [open, setOpen] = useState(false);

  const userColumns = [
    { field: "settings.username", headerName: "Username", hideInForm: true },
    { field: "balance", headerName: "Balance" },
    { field: "roles", headerName: "Roles" },
  ];

  const fetchUsers = async ({ page, limit, search }) => {
    const params = { page: page + 1, limit, search };
    return await api.get("/users", { params });
  };

  const handleEdit = (user) => {
    setSelectedUser(user);
    setOpen(true);
  };

  const handleDelete = async (user) => {
    if (confirm(`Delete user ${user.username}?`)) {
      await api.delete(`/users/${user._id}`);
      window.location.reload();
    }
  };

  return (
    <>
      <DataTable
        fetchData={fetchUsers}
        columns={userColumns}
        onEdit={handleEdit}
        onDelete={handleDelete}
      />
      {open && (
        <AdminFormDialog
          entity={selectedUser}
          endpoint="/users"
          columns={userColumns}
          title="User"
          onClose={() => {
            setOpen(false);
            window.location.reload();
          }}
        />
      )}
    </>
  );
}
